import { readFileSync, writeFileSync, mkdirSync } from 'fs'
import { dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const repoRoot = `${__dirname}/..`

const js = readFileSync('/tmp/dvbuild.js', 'utf8')
const escaped = js.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${')
const out = `// AUTO-GENERATED by \`just webview-build\` — do not edit manually\nexport const DOCUMENT_VIEWER_JS = \`${escaped}\`\n`

const outDir = `${repoRoot}/app/src/webview`
mkdirSync(outDir, { recursive: true })
writeFileSync(`${outDir}/document-viewer-bundle.ts`, out)
console.log('document-viewer-bundle.ts written')
